module RefModule(
  input clk_in,
  input reset,
  output reg clk_out
);parameter divide_by = 2;

reg [31:0] obf_counter;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    clk_out <= 1'b0;
    obf_counter <= 0;
  end
  else begin
    if (obf_counter == divide_by - 1) begin
      clk_out <= ~clk_out;
      obf_counter <= 0;
    end
    else begin
      obf_counter <= obf_counter + 1;
    end
  end
end

endmodule
